/// <summary>
/// This class is an extension of form EcoResProductDetailsExtended and dataSources Sales.
/// </summary>
[ExtensionOf(formDataSourceStr(EcoResProductDetailsExtended, Sales))]
internal final class ETGEcoResProductDetailsExtended_Extension
{
}

Method.Source:
/// <summary>
/// Contains the logic for the fields mandatory, visibility and editable/non editable when CylinderTracking feature is enabled
/// and Depositneeded field is Yes.
/// </summary>
/// <returns></returns>
public int active()
{
    int ret =  next active();
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        this.object(fieldNum(InventTableModule, ETGPackSize)).mandatory(element.Sales.ETGDepositNeeded == NoYes::Yes);
        this.object(fieldNum(InventTableModule, ETGPackSize)).allowEdit(element.Sales.ETGDepositNeeded == NoYes::Yes);
    }
    else
    {
        this.object(fieldNum(InventTableModule, ETGPackSize)).mandatory(false);
        this.object(fieldNum(InventTableModule, ETGPackSize)).allowEdit(false);
        this.object(fieldNum(InventTableModule, ETGPackSize)).visible(false);
        this.object(fieldNum(InventTableModule, ETGDepositNeeded)).visible(false);
        this.object(fieldNum(InventTableModule, ETGFilledEmptyNeeded)).visible(false);
    }

    // Freezes the form fields by updating the design when the data source is activated.
    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);
    //

    return ret;
}
